const GATE_COLOR={bank:'#63ff9a',split:'#41e8ff',greed:'#ff3df2',perfect:'#ffd35a'};
const GATE_TIP={bank:'GRØN = BANK · gem dine point', split:'CYAN = SPLIT · bank halvdelen', greed:'PINK = GRÅDIG · boost x', perfect:'GUL = PERFEKT · ram midten'};

function showMenu(){ state='menu'; $('menu').style.display='flex'; $('duelBar').style.display='none'; refreshMenu(); engineUpdate(); }
function hideMenu(){ $('menu').style.display='none'; }
function hideGameOver(){ $('gameOver').style.display='none'; $('gameOver').classList.remove('arm'); }

function startMode(mode){
  if(mode==='campaign'){
    if(!save.campaign) save.campaign={unlocked:1,current:1,stars:{}};
    startCampaignLevel(save.campaign.current || save.campaign.unlocked || 1);
    return;
  }
  if(mode==='daily'){
    ensureDailyRun();
    if(save.dailyRun.tries>=3){
      toast('Ingen forsøg tilbage i dag. Minen åbner igen i morgen.');
      activeTab='leaderboard'; renderTab();
      return;
    }
    duelTarget=null;
    startGame('daily', todaySeed());
  } else {
    duelTarget=null;
    startGame(mode, randomSeed());
  }
}
function retryRun(){
  if(state!=='over') return;
  hideGameOver();
  if(currentMode==='daily'){
    ensureDailyRun();
    if(save.dailyRun.tries>=3){ toast('Ingen forsøg tilbage i dag.'); showMenu(); return; }
    startGame('daily', todaySeed());
  } else {
    startGame(currentMode, currentSeed);
  }
}
function startDuel(seed, targetScore, name){
  duelTarget={score:targetScore, name:name||'Ukendt dværg'};
  activeCampaignLevel=null;
  startGame('duel', seed);
}
function startCampaignLevel(id){
  if(!save.campaign) save.campaign={unlocked:1,current:1,stars:{}};
  id=clamp(Math.floor(id||1),1,CAMPAIGN_LEVELS.length);
  if(id>(save.campaign.unlocked||1)){ toast('Bane låst. Spil den forrige. Revolutionerende system.'); return; }
  activeCampaignLevel=CAMPAIGN_LEVELS.find(l=>l.id===id) || CAMPAIGN_LEVELS[0];
  save.campaign.current=id;
  duelTarget=null;
  persist();
  startGame('campaign', activeCampaignLevel.seed);
}

function startGame(mode,seed){
  currentMode=mode; currentSeed=seed>>>0;
  if(mode==='campaign' && activeCampaignLevel){
    modeMods={
      speed:activeCampaignLevel.speed,
      coins:activeCampaignLevel.coins,
      hazards:activeCampaignLevel.hazards,
      label:'Kampagne '+activeCampaignLevel.id,
      fair:false,
      campaign:true,
      length:activeCampaignLevel.length,
      width:activeCampaignLevel.width
    };
  } else {
    modeMods = {
      daily:{speed:1, coins:1, hazards:1, label:'Dagens Mine', fair:true},
      duel:{speed:1, coins:1, hazards:1, label:'DUEL', fair:true},
      survival:{speed:1.02, coins:1.42, hazards:1.62, label:'Overlevelse', fair:false, survival:true, length:270, width:.94},
      random:{speed:1, coins:1, hazards:1, label:'Random', fair:false},
      practice:{speed:.85, coins:.6, hazards:.65, label:'Træning', fair:false},
      chaos:{speed:1.15, coins:1.55, hazards:1.45, label:'Kaos', fair:false}
    }[mode] || {speed:1,coins:1,hazards:1,label:mode,fair:false};
  }
  runStatsCache = modeMods.fair ? Object.assign({},FAIR_STATS) : buildStats();
  hideMenu(); hideGameOver(); $('pauseOv').style.display='none';
  state='play';
  track=makeTrack(currentSeed);
  gates=makeGates(currentSeed);
  coins=makeCoins(currentSeed, modeMods);
  hazards=makeHazards(currentSeed, modeMods);
  weaponCrates=makeWeaponCrates(currentSeed, modeMods);
  gi=0; ci=0; hi=0; wi=0;
  particles=[]; floating=[];
  dwarf={ sx:clamp(W*0.24,90,170), y:H*0.5, py:H*0.5, vy:0, r:18, hitR:10.5, rot:0, inv:1.0, shield:0, magnet:0, dash:0, slow:0, over:0 };
  camX=0; pCamX=0; dist=0;
  score=0; banked=0; livePot=0; mult=1; peak=1; skips=0; perfects=0; collectedGold=0; smashed=0; nearCount=0;
  coinCombo=0; lastCoinT=-9;
  grazeT=0; grazeTick=0; grazeTotal=0;
  recordHit=false; bestAtStart=save.best;
  simTick=0; acc=0; inputLevel=0; inputDown=false;
  hammerCd=0; weaponCd=0; survivalWave=1; lastWave=1; survivalKills=0; shieldHp=1+Math.floor(runStatsCache.hp||0);
  ultCharge=0; bankBoostT=0; autoPerfectN=0; weaponBoostT=0; ultFlashT=0; runData=0;
  runChar = modeMods.fair ? 'bram' : activeChar();
  freezeT=0; dieT=0; shakeMag=0; flashA=0;
  runGhost=[]; ghost=loadGhost(currentSeed);
  $('modeBadge').textContent=modeMods.label;
  if(mode==='survival'){ $('subInfo').textContent='Wave 1 · loot jagt'; }
  else if(mode==='campaign' && activeCampaignLevel){ $('subInfo').textContent=activeCampaignLevel.name; }
  else if(mode==='daily'){ ensureDailyRun(); $('subInfo').textContent='forsøg '+(save.dailyRun.tries+1)+'/3'; }
  else if(mode==='duel' && duelTarget){ $('subInfo').textContent='mål '+fmt(duelTarget.score); }
  else { $('subInfo').textContent='seed '+String(currentSeed).slice(0,6); }
  $('fairPill').style.display = modeMods.fair ? 'inline-block' : 'none';
  if(mode==='duel' && duelTarget){
    $('duelBar').style.display='block';
    $('duelName').textContent='DUEL mod '+duelTarget.name+' · slå '+fmt(duelTarget.score);
    $('duelFill').style.width='0%';
  } else if(mode==='campaign' && activeCampaignLevel){
    $('duelBar').style.display='block';
    $('duelName').textContent='KAMPAGNE '+activeCampaignLevel.id+' · '+objectiveText(activeCampaignLevel.goal);
    $('duelFill').style.width='0%';
  } else { $('duelBar').style.display='none'; }
  if(!save.seenIntro){ introPhase=1; heldT=0; $('introText').textContent='HOLD SKÆRMEN = STIG'; $('intro').style.display='flex'; }
  else { introPhase=0; $('intro').style.display='none'; }
  flash(modeMods.label+' — KLAR!');
  hudDirty=true;
  last=now();
  requestAnimationFrame(loop);
}


/* ===== 12-verden-resize-sikker-y-gemmes-som-broeker.js ===== */
/* ================= VERDEN (resize-sikker: y gemmes som brøker) ================= */
function makeTrack(seed){
  const r=mulberry32(seed^0xABCDEF);
  const points=[];
  let center=0.5, width=0.34;
  const N=(modeMods && modeMods.length) ? modeMods.length : 150;
  for(let i=0;i<N;i++){
    center = clamp(center + (r()-.5)*0.14, .23, .77);
    const shrink = Math.min(.19, i/N*.17);
    width = clamp((.38 - shrink + (r()-.5)*.05) * ((modeMods && modeMods.width) || 1), .135, .46);
    if(i%17===0) width*=0.72;
    points.push({x:i*190, c:center, w:width});
  }
  trackEndX=(N-1)*190;
  return points;
}
function sampleTrack(x){
  const step=190;
  const i=clamp(Math.floor(x/step),0,track.length-2);
  const t=clamp((x-track[i].x)/step,0,1);
  const c=lerp(track[i].c,track[i+1].c,t);
  const w=lerp(track[i].w,track[i+1].w,t);
  const mid=c*H, half=w*H;
  return {top:mid-half, bot:mid+half, mid, half};
}
function makeGates(seed){
  const r=mulberry32(seed^0x12345);
  const arr=[];
  const types=['bank','split','greed','perfect'];
  let x=560;
  for(let i=0;i<60;i++){
    x += 360 + r()*210;
    if(x>trackEndX-700) break;
    const type=types[Math.floor(r()*types.length)];
    arr.push({
      x, type,
      o:(r()-.5)*2,
      decay:Math.max(.62, 1-i*.006),
      gapBase: type==='perfect'?0.082:0.108,
      used:false, skipped:false, seen:false
    });
  }
  return arr;
}
function gateGeom(g){
  const s=sampleTrack(g.x);
  const gap=g.gapBase*H*g.decay;
  const y=clamp(s.mid + g.o*s.half*1.15, s.top+gap, s.bot-gap);
  return {y,gap};
}
function makeCoins(seed,mods){
  const r=mulberry32(seed^0x9876);
  const arr=[];
  const n=Math.floor(185*mods.coins);
  for(let i=0;i<n;i++){
    const x=340+r()*(trackEndX-1100);
    const tF=r();
    const val=r()<.12?5:1;
    arr.push({x,tF,val,taken:false,r:(val===5?8:5),px:null,py:0});
  }
  arr.sort(function(a,b){return a.x-b.x;});
  return arr;
}
function makeHazards(seed,mods){
  const r=mulberry32(seed^0xFEED);
  const arr=[];
  const n=Math.floor(132*mods.hazards);
  const sv=(mods&&mods.survival)?1.22:1;
  for(let i=0;i<n;i++){
    const x=760+r()*(trackEndX-1400);
    const roll=r();
    // bat ~38% · rock ~26% · spike ~16% · saw ~13% · crystal ~7%
    const type = roll<.38?'bat' : roll<.64?'rock' : roll<.80?'spike' : roll<.93?'saw' : 'crystal';
    const baseHp = type==='rock'?2.2 : type==='bat'?1.0 : type==='spike'?1.7 : type==='saw'?3.6 : 7.0;
    // jo længere inde i banen, jo sejere farer — belønner våben-investering og holder presset oppe
    const depth = 1 + (x/Math.max(1,trackEndX))*0.85;
    const hp = baseHp * sv * depth * (type==='crystal'?(1+ (mods&&mods.survival?0.5:0)):1);
    arr.push({
      x,type,
      edge:r()<.5?'top':'bot',
      tF:r(),
      phase:r()*Math.PI*2,
      amp: type==='saw' ? (26+r()*24) : (8+r()*9),
      dead:false, near:false, counted:false,
      r:(type==='rock'?17:type==='bat'?14:type==='spike'?20:type==='saw'?22:19),
      hitR:(type==='rock'?10:type==='bat'?6.5:type==='spike'?12:type==='saw'?12.5:11),
      hp:hp, hpMax:hp
    });
  }
  arr.sort(function(a,b){return a.x-b.x;});
  return arr;
}

function makeWeaponCrates(seed,mods){
  const r=mulberry32(seed^0xC0FFEE);
  const arr=[];
  const n=Math.floor((mods&&mods.survival?58:20) * ((mods&&mods.coins)||1));
  for(let i=0;i<n;i++){
    const x=520 + r()*(trackEndX-950);
    const roll=r();
    const kind = roll<0.24 ? 'weapon' : roll<0.70 ? 'scrap' : roll<0.84 ? 'medkit' : 'relic';
    const weights = kind==='weapon'
      ? (r()<.52?'crossbow':r()<.75?'chain':r()<.89?'blunder':r()<.97?'drillgun':'runeblade')
      : null;
    arr.push({x,tF:r(),kind,weapon:weights,taken:false,px:null,py:0,r:13});
  }
  arr.sort(function(a,b){return a.x-b.x;});
  return arr;
}

function hazardY(h,s){
  if(h.type==='spike') return h.edge==='top'? s.top+12 : s.bot-12;
  const base=lerp(s.top+35,s.bot-35,h.tF);
  if(h.type==='bat') return base + Math.sin(simTick*SIM_DT*4 + h.phase)*h.amp;
  if(h.type==='saw') return base + Math.sin(simTick*SIM_DT*6 + h.phase)*h.amp;
  return base; // rock + crystal stationary
}
function loadGhost(seed){
  const g=save.ghosts2[String(seed)];
  if(!g || !Array.isArray(g.path) || g.path.length<4) return null;
  return g;
}
function saveGhost(seed,path,scoreVal){
  const k=String(seed);
  const old=save.ghosts2[k];
  if(!old || scoreVal>old.score){
    save.ghosts2[k]={score:scoreVal,path:path.slice(0,1600)};
    const keys=Object.keys(save.ghosts2);
    if(keys.length>25) delete save.ghosts2[keys[0]];
  }
}


/* ===== 13-fx-hjaelpere.js ===== */
/* ================= FX-HJÆLPERE ================= */
function shake(m){ shakeMag=Math.max(shakeMag,m); }
function flashScreen(col,a){ flashCol=col; flashA=Math.max(flashA,a); }
function addParticle(x,y,color,count,power){
  count=count||8; power=power||1;
  if(particles.length>240) return;
  for(let i=0;i<count;i++){
    const a=Math.random()*Math.PI*2, sp=(80+Math.random()*220)*power;
    particles.push({x,y,vx:Math.cos(a)*sp,vy:Math.sin(a)*sp,life:.35+Math.random()*.35,color});
  }
}
function confetti(x,y){
  const cols=['#ffd35a','#41e8ff','#ff3df2','#63ff9a'];
  for(let i=0;i<36;i++){
    const a=Math.random()*Math.PI*2, sp=120+Math.random()*320;
    particles.push({x,y,vx:Math.cos(a)*sp,vy:Math.sin(a)*sp-160,life:.6+Math.random()*.5,color:cols[i%4]});
  }
}
function floatText(x,y,text,color){
  floating.push({x,y,text,color:color||'#fff',life:1});
}
function pumpMult(){
  const el=$('multVal');
  el.classList.remove('pump');
  void el.offsetWidth;
  el.classList.add('pump');
  setTimeout(function(){el.classList.remove('pump');},140);
}


/* ===== 14-evne.js ===== */
/* ================= EVNE ================= */
function triggerAbility(){
  if(state!=='play'||hammerCd>0) return;
  const st=runStatsCache;
  const ab = modeMods.fair ? 'hammer' : save.selected.ability;
  hammerCd = Math.max(.9, 1.8 - (st.hammer||0) - (st.cd||0));
  if(ab==='dash'){
    dwarf.dash=.36; dwarf.inv=.36; flash('BERSÆRK DASH');
    addParticle(camX+dwarf.sx,dwarf.y,'#ff9d3d',24,1.5);
    sfx.skip();
  }else if(ab==='shield'){
    dwarf.shield=2.2; dwarf.inv=.5; flash('SKJOLDBRØL');
    addParticle(camX+dwarf.sx,dwarf.y,'#41e8ff',20,1.1);
    sfx.split();
  }else if(ab==='magnet'){
    dwarf.magnet=3.8; flash('GULDMAGNET');
    addParticle(camX+dwarf.sx,dwarf.y,'#ffd35a',18,1);
    sfx.coin(4);
  }else if(ab==='drill'){
    flash('TUNNELBOR!');
    drillBlast();
  }else if(ab==='chrono'){
    dwarf.slow=2.15; dwarf.inv=.35; flash('TIDSSPRÆKKE');
    flashScreen('#41e8ff',.28); sfx.perfect(); shake(5);
  }else if(ab==='overcharge'){
    dwarf.over=2.2; mult*=1.42; livePot+=260*mult; flash('OVERLADNING x'+mult.toFixed(2));
    flashScreen('#ff3df2',.32); sfx.skip(); pumpMult(); shake(8);
  }else{
    flash('HAMMER!');
    smashAhead();
  }
  buzz(15);
}

function drillBlast(){
  const wx=camX+dwarf.sx;
  let hit=0;
  for(let i=hi;i<hazards.length;i++){
    const h=hazards[i];
    if(h.x>wx+260) break;
    if(h.dead) continue;
    const sh=sampleTrack(h.x), hy=hazardY(h,sh);
    if(h.x>wx-25 && Math.abs(hy-dwarf.y)<115){
      killHazard(h,hy,'BOR',1.25); hit++; smashed++;
    }
  }
  if(hit){ sfx.smash(); shake(13); flashScreen('#ff9d3d',.28); missionAdd('bats',hit); }
  else { sfx.ui(); }
}

function smashAhead(){
  const wx=camX+dwarf.sx;
  let hit=0;
  for(let i=hi;i<hazards.length;i++){
    const h=hazards[i];
    if(h.x>wx+170) break;
    if(h.dead) continue;
    const s=sampleTrack(h.x);
    const hy=hazardY(h,s);
    const dx=h.x-wx, dy=hy-dwarf.y;
    if(dx>-20 && dx<150 && Math.abs(dy)<80){
      killHazard(h,hy,'SMASH',1); hit++; smashed++;
    }
  }
  if(hit){ sfx.smash(); shake(7); missionAdd('bats',hit); if(smashed>=10) unlock('batkiller'); }
  else sfx.ui();
}


/* ===== 15-ultimate-kun-pve-fair-modes-laast-til-bram.js ===== */
/* ================= ULTIMATE (kun PvE — fair modes låst til Bram) ================= */
function addUlt(n){
  if(state!=='play') return;
  ultCharge = Math.min(1, ultCharge + n*(1+(runStatsCache?(runStatsCache.ultcharge||0):0)));
}
function clearHazardsOnScreen(reason, rmul, scoreEach){
  const wx=camX+dwarf.sx; let hit=0;
  for(let i=hi;i<hazards.length;i++){
    const h=hazards[i];
    if(h.x>wx+W) break;
    if(h.dead || h.x<wx-120) continue;
    const sh=sampleTrack(h.x), hy=hazardY(h,sh);
    killHazard(h,hy,reason,rmul||1); smashed++; hit++;
    if(scoreEach) livePot+=scoreEach*mult;
  }
  if(hit) missionAdd('bats',hit);
  return hit;
}
function triggerUltimate(){
  if(state!=='play' || ultCharge<1) return;
  ultCharge=0; ultFlashT=0.6;
  const c=CHARACTERS[runChar]||CHARACTERS.bram;
  const wx=camX+dwarf.sx;
  flash(c.ultName.toUpperCase()+'!');
  flashScreen(c.color||'#ffd35a',.42); shake(16); sfx.record(); buzz(40);
  confetti(wx,dwarf.y-30);
  switch(runChar){
    case 'bram':{ // Guldregn
      const grab=livePot*0.55*2;
      banked+=grab; livePot*=0.45; bankBoostT=4; mult=Math.max(1,mult*1.12);
      floatText(wx,dwarf.y-60,'GULDREGN +'+fmt(grab),'#ffd35a');
      for(let i=0;i<3;i++) addParticle(wx+i*8,dwarf.y,'#ffd35a',18,1.4);
      sfx.bank(true); break; }
    case 'ragnar':{ // Blodrus
      mult*=1.8; dwarf.inv=3.5; dwarf.over=3.5; livePot+=300*mult;
      floatText(wx,dwarf.y-60,'BLODRUS x'+mult.toFixed(2),'#ff496c');
      flashScreen('#ff3df2',.3); pumpMult(); break; }
    case 'frida':{ // Nålestik
      dwarf.slow=4; autoPerfectN=3; dwarf.inv=1.2;
      floatText(wx,dwarf.y-60,'NÅLESTIK · 3 auto-perfekt','#b388ff');
      flashScreen('#41e8ff',.3); sfx.perfect(); break; }
    case 'ulf':{ // Jordskælv
      const hit=clearHazardsOnScreen('SKÆLV',1.2,120);
      shieldHp=Math.min(ultShieldCap(), shieldHp+2);
      livePot+=400*mult;
      floatText(wx,dwarf.y-60,'JORDSKÆLV · '+hit+' knust','#ffb347');
      sfx.smash(); break; }
    case 'sigrid':{ // Krudttønde
      let hit=0;
      for(let i=hi;i<hazards.length;i++){
        const h=hazards[i];
        if(h.x>wx+W*1.3) break;
        if(h.dead || h.x<wx-60) continue;
        const sh=sampleTrack(h.x), hy=hazardY(h,sh);
        killHazard(h,hy,'SPRÆNG',1.5); smashed++; hit++;
      }
      if(hit) missionAdd('bats',hit);
      livePot+=520*mult; gainScrap(60+hit*8, wx, dwarf.y);
      floatText(wx,dwarf.y-60,'KRUDTTØNDE · '+hit+' væk','#ff7a3d');
      sfx.smash(); shake(20); break; }
    case 'grim':{ // Støvsuger-storm
      let got=0;
      for(let i=ci;i<coins.length;i++){
        const co=coins[i];
        const cx=co.px===null?co.x:co.px;
        if(cx>wx+W) break;
        if(co.taken || cx<camX-80) continue;
        co.taken=true;
        const gain=Math.ceil(co.val*(1+(runStatsCache.coin||0)));
        collectedGold+=gain; livePot+=gain*12*mult; got+=gain;
      }
      for(let i=wi;i<weaponCrates.length;i++){
        const cr=weaponCrates[i];
        const cx=cr.px===null?cr.x:cr.px;
        if(cx>wx+W) break;
        if(cr.taken || cx<camX-120) continue;
        collectWeaponCrate(cr,cx,cr.py||dwarf.y);
      }
      livePot+=got*4*mult;
      floatText(wx,dwarf.y-60,'STØVSUGER-STORM +'+fmt(got)+'g','#ffd35a');
      sfx.coin(6); break; }
    case 'thorin':{ // Sidste Ord
      shieldHp=ultShieldCap(); mult*=1.5; dwarf.over=3; dwarf.inv=1.5;
      clearHazardsOnScreen('SIDSTE ORD',1,80);
      livePot+=260*mult;
      floatText(wx,dwarf.y-60,'SIDSTE ORD · fuld HP','#63ff9a');
      flashScreen('#63ff9a',.32); pumpMult(); break; }
    case 'volund':{ // Rune-overladning
      weaponBoostT=6; mult*=1.35; dwarf.inv=1.0;
      floatText(wx,dwarf.y-60,'RUNE-OVERLADNING · våben x1.6','#7CF6E3');
      flashScreen('#7CF6E3',.32); sfx.skip(); pumpMult(); break; }
    default: livePot+=200*mult;
  }
  score=banked+livePot;
  hudDirty=true;
}
function ultShieldCap(){ return modeMods.survival?6:5; }


/* ===== 16-sim-fixed-timestep-fair-paa-alle-skaerme.js ===== */
/* ================= SIM (fixed timestep — fair på alle skærme) ================= */

function killHazard(h, hy, reason, rewardMul){
  if(!h || h.dead) return;
  h.dead=true;
  survivalKills++;
  if(h.type==='crystal'){
    const st=runStatsCache||{};
    const goldR = 220 * (rewardMul||1) * mult;
    livePot += goldR;
    addUlt(0.12);
    const dataAmt = Math.max(1, Math.round((2 + survivalWave*0.3) * (1+(st.data||0)*0.6) * (1+(researchBonusStats().data||0)*0.6)));
    gainData(dataAmt, h.x, hy-18);
    gainScrap(70 + Math.floor(Math.random()*70) + survivalWave*4, h.x, hy+18);
    addParticle(h.x,hy,'#7CF6E3',24,1.6);
    addParticle(h.x,hy,'#b388ff',14,1.2);
    floatText(h.x,hy,'KRYSTAL +'+Math.floor(goldR),'#7CF6E3');
    flashScreen('#7CF6E3',.18); sfx.perfect();
    persist();
    return;
  }
  const reward=(reason==='WEAPON'?75:60) * (rewardMul||1) * mult;
  livePot += reward;
  if(currentMode==='survival'){
    livePot += 18*survivalWave*mult;
    // Mere konkret progression: kills giver små mængder skrot, så runs altid føles brugbare.
    if(reason==='WEAPON' || reason==='SMASH' || reason==='BOR' || reason==='PARRY'){
      const scrapDrip = 2 + Math.floor(survivalWave*0.55) + (h.type==='saw'?2:0);
      gainScrap(scrapDrip, h.x, hy+16);
    }
  }
  addUlt(0.06);
  addParticle(h.x,hy,reason==='WEAPON'?'#ffd35a':'#ff9d3d',16,1.25);
  floatText(h.x,hy,(reason||'KILL')+' +'+Math.floor(reward), reason==='WEAPON'?'#ffd35a':'#ff9d3d');
  if(Math.random() < (currentMode==='survival'?0.28:0.10)){
    const roll=Math.random();
    const kind = roll<0.13?'weapon':roll<0.72?'scrap':roll<0.86?'medkit':'relic';
    weaponCrates.push({x:h.x+30,tF:clamp(hy/H,0.1,0.9),kind:kind,weapon:null,taken:false,px:h.x+30,py:hy,r:12});
    weaponCrates.sort(function(a,b){return a.x-b.x;});
  }
}
function autoFireWeapon(dt, wx){
  ensureInventory();
  const key=currentWeaponKey();
  const w=WEAPONS[key]; if(!w) return;
  const st=weaponStats(key);
  weaponCd-=dt;
  if(weaponCd>0) return;
  const wmul = 1 + (runStatsCache.weapon||0);
  const boosting = weaponBoostT>0;
  const dmg = st.damage * wmul * (boosting?1.6:1);
  let targets=[];
  for(let i=hi;i<hazards.length;i++){
    const h=hazards[i];
    if(h.x>wx+st.range) break;
    if(h.dead || h.x<wx+18) continue;
    const sh=sampleTrack(h.x), hy=hazardY(h,sh);
    const dy=Math.abs(hy-dwarf.y);
    const cone = key==='blunder' ? 92 : key==='chain' ? 62 : 48;
    if(dy<cone) targets.push({h,hy,d:h.x-wx+dy*.35});
  }
  if(!targets.length) return;
  targets.sort((a,b)=>a.d-b.d);
  const pierce=(st.pierce||1) + (boosting?2:0);
  for(let i=0;i<Math.min(pierce,targets.length);i++){
    const t=targets[i];
    t.h.hp=(t.h.hp||1)-dmg;
    addParticle(wx+24,dwarf.y,'#ffd35a',4,0.55);
    addParticle(t.h.x,t.hy,'#ffd35a',8,0.85);
    floatText(t.h.x,t.hy,'-'+dmg.toFixed(1),'#ffd35a');
    if(t.h.hp<=0){
      killHazard(t.h,t.hy,'WEAPON',1+(st.leech||0));
      if(st.leech) livePot+=90*mult*st.leech;
    }
  }
  weaponCd=st.cooldown * (boosting?0.4:1);
  sfx.tick();
}
function collectWeaponCrate(c,cx,cy){
  c.taken=true;
  if(c.kind==='weapon'){
    const key=c.weapon || WEAPON_DROP_POOL[Math.floor(Math.random()*WEAPON_DROP_POOL.length)];
    gainWeapon(key,{x:cx,y:cy});
  }else if(c.kind==='medkit'){
    shieldHp=Math.min(shieldHp+1, ultShieldCap());
    floatText(cx,cy,'+1 HP','#63ff9a'); sfx.bank(false);
  }else if(c.kind==='relic'){
    // Relics giver nu run-specifikke buffs, ikke bare lidt tal-konfetti.
    const r=Math.random();
    if(r<0.25){
      weaponBoostT += 5.5;
      floatText(cx,cy,'RELIK: VÅBENRUS','#ffd35a');
    }else if(r<0.50){
      dwarf.magnet += 5.5;
      floatText(cx,cy,'RELIK: STOR-SUG','#41e8ff');
    }else if(r<0.75){
      bankBoostT += 5.5;
      floatText(cx,cy,'RELIK: BANKBOOST','#63ff9a');
    }else{
      shieldHp=Math.min(ultShieldCap(), shieldHp+1);
      floatText(cx,cy,'RELIK: +1 HP','#63ff9a');
    }
    mult*=1.18; livePot+=360*mult;
    sfx.perfect(); pumpMult(); flashScreen('#ff3df2',.18);
  }else{
    const scrap=45 + Math.floor(Math.random()*55) + (currentMode==='survival'?survivalWave*5:0);
    gainScrap(scrap,cx,cy);
    sfx.coin(3);
  }
  addParticle(cx,cy,'#bfc7d9',12,1.0);
  persist();
}

function stepSim(){
  simTick++;
  const dt=SIM_DT;
  const st=runStatsCache;
  pCamX=camX; dwarf.py=dwarf.y;

  let speed=(190 + dist*0.0025 + (st.speed||0)*120) * modeMods.speed;
  if(dwarf.dash>0) speed+=220;
  if(dwarf.slow>0) speed*=0.58;
  if(dwarf.over>0) speed*=1.10;
  if(modeMods.survival) speed *= 1 + Math.min(1.0,(survivalWave-1)*0.05);
  camX += speed*dt; dist=camX;

  const spdN=clamp((speed-190)/280,0,1);
  const targetSX=clamp(W*(0.26-0.08*spdN),86,180);
  dwarf.sx += (targetSX-dwarf.sx)*Math.min(1,dt*3);
  const wx=camX+dwarf.sx;

  const lift=620*(1+(st.lift||0)*0.8);
  const grav=455*(1-(st.control||0)*0.22);
  inputLevel += ((inputDown?1:0)-inputLevel)*(1-Math.pow(0.02,dt*8));
  dwarf.vy += (grav*(1-inputLevel) - lift*inputLevel)*dt;
  if(dwarf.dash>0){ dwarf.dash-=dt; dwarf.vy*=.94; }
  const damp=0.982-(st.control||0)*0.035;
  dwarf.vy *= Math.pow(damp, dt*60);
  dwarf.vy=clamp(dwarf.vy,-390,430);
  dwarf.y += dwarf.vy*dt;
  dwarf.rot = lerp(dwarf.rot, clamp(dwarf.vy/360,-0.95,0.95), .10);

  if(hammerCd>0) hammerCd-=dt;
  dwarf.inv=Math.max(0,dwarf.inv-dt);
  dwarf.shield=Math.max(0,dwarf.shield-dt);
  dwarf.magnet=Math.max(0,dwarf.magnet-dt);
  dwarf.slow=Math.max(0,dwarf.slow-dt);
  dwarf.over=Math.max(0,dwarf.over-dt);
  if(bankBoostT>0) bankBoostT-=dt;
  if(weaponBoostT>0) weaponBoostT-=dt;
  if(ultFlashT>0) ultFlashT-=dt;
  addUlt(dt*0.018);

  const s=sampleTrack(wx);
  const topGap=(dwarf.y-dwarf.hitR)-s.top;
  const botGap=s.bot-(dwarf.y+dwarf.hitR);
  if(topGap<0 || botGap<0){
    damageOrEnd('Minevæg. Hitboxen er lille — den her var din egen.');
    if(state!=='play') return;
    dwarf.y=clamp(dwarf.y, s.top+dwarf.hitR+2, s.bot-dwarf.hitR-2);
    dwarf.vy*=-0.25;
  } else {
    const g=Math.min(topGap,botGap);
    if(g<11){
      grazeT+=dt; grazeTotal+=dt; grazeTick+=dt;
      if(grazeTick>=0.2){
        grazeTick=0;
        mult+=0.035; livePot+=14*mult; addUlt(0.02);
        const sideY = topGap<botGap ? s.top+2 : s.bot-2;
        addParticle(wx-6,sideY,'#41e8ff',2,0.5);
        floatText(wx,sideY+(topGap<botGap?24:-24),'+kys','#41e8ff');
        sfx.tick();
      }
      if(grazeTotal>=6) unlock('graze');
    } else { grazeT=0; grazeTick=0; }
  }

  mult += dt*(0.075 + skips*.012 + (st.greed||0)*.05);
  peak=Math.max(peak,mult);
  livePot += dt*95*mult*(1+(st.greed||0));
  if(st.interest && banked>0) livePot += dt * Math.min(80, banked/900) * st.interest;
  if(modeMods.survival){
    survivalWave=Math.max(1, Math.floor(dist/900)+1);
    if(survivalWave!==lastWave){
      lastWave=survivalWave;
      shieldHp=Math.min(ultShieldCap(), shieldHp + (survivalWave%3===0?1:0));
      if(survivalWave>=8) unlock('survivor');
      flash('WAVE '+survivalWave+(survivalWave%5===0?' · MINIBOSS!':''));
      if(survivalWave%4===0){
        // små belønningskasser efter milestones, fordi ren smerte er dårlig retention. Utroligt nok.
        weaponCrates.push({x:camX+dwarf.sx+W*0.72,tF:0.45,kind:'relic',weapon:null,taken:false,px:null,py:0,r:13});
        weaponCrates.push({x:camX+dwarf.sx+W*0.82,tF:0.58,kind:'scrap',weapon:null,taken:false,px:null,py:0,r:13});
        weaponCrates.sort(function(a,b){return a.x-b.x;});
      }
      flashScreen('#63ff9a',.18); sfx.level();
    }
    mult += dt*0.012*survivalWave;
    livePot += dt*survivalWave*18;
    $('subInfo').textContent='Wave '+survivalWave+' · kills '+survivalKills+' · '+WEAPONS[currentWeaponKey()].name;
  }
  autoFireWeapon(dt, wx);
  score=banked+livePot;

  if(!recordHit && bestAtStart>500 && score>bestAtStart){
    recordHit=true;
    flashScreen('#ffd35a',.45); shake(13);
    floatText(wx,dwarf.y-70,'NY REKORD!','#ffd35a');
    confetti(wx,dwarf.y-30);
    sfx.record();
  }

  if(wx>=trackEndX-40){
    banked+=livePot; livePot=0; score=banked;
    sfx.finish(); flashScreen('#63ff9a',.5);
    endRun(true,'MÅL! Du nåede udgangen i live — hele potten banket.');
    return;
  }

  // Porte
  for(let i=gi;i<gates.length;i++){
    const g=gates[i];
    if(g.x>wx+W) break;
    if(g.used) continue;
    const geom=gateGeom(g);
    if(!g.seen && !save.seenGates[g.type] && g.x>wx && g.x-wx<W*0.72){
      g.seen=true; save.seenGates[g.type]=1;
      floatText(g.x, Math.max(60,geom.y-geom.gap-46), GATE_TIP[g.type], GATE_COLOR[g.type]);
    }
    if(g.x < wx-40){
      g.used=true; g.skipped=true; skips++; missionAdd('skips',1);
      mult *= (1.22 + (st.greed||0)*.55);
      floatText(g.x,geom.y,'SKIP x'+mult.toFixed(2),'#ff3df2');
      addParticle(g.x,geom.y,'#ff3df2',12,1.1);
      sfx.skip(); pumpMult();
      continue;
    }
    if(Math.abs(g.x-wx)<24 && Math.abs(geom.y-dwarf.y)<geom.gap){
      g.used=true;
      handleGate(g, geom, st);
    }
  }
  while(gates[gi] && gates[gi].used) gi++;

  // Mønter (front-støvsuger)
  const nozzleX=wx+30, nozzleY=dwarf.y-3;
  const vacLen=145+(st.magnet||0)*130+(dwarf.magnet>0?120:0);
  const vacHalf=36+(st.magnet||0)*38+(dwarf.magnet>0?26:0);
  if(simTick*SIM_DT - lastCoinT > 1.4) coinCombo=0;
  for(let i=ci;i<coins.length;i++){
    const c=coins[i];
    if(c.px===null && c.x>wx+W+140) break;
    if(c.taken) continue;
    let cx, cy;
    if(c.px===null){
      const sc=sampleTrack(c.x);
      cx=c.x; cy=lerp(sc.top+35,sc.bot-35,c.tF);
    } else { cx=c.px; cy=c.py; }
    const dx=cx-nozzleX, dy=cy-nozzleY;
    if(dx<-32 || dx>vacLen+40 || Math.abs(dy)>vacHalf+55) continue;
    const cone=vacHalf*(1-clamp(dx/vacLen,0,1)*0.45);
    if(dx>-12 && dx<vacLen && Math.abs(dy)<cone){
      if(c.px===null){ c.px=cx; c.py=cy; }
      const pull=(7.5+(st.magnet||0)*5+(dwarf.magnet>0?5:0))*dt;
      c.px += (nozzleX-c.px)*pull;
      c.py += (nozzleY-c.py)*pull;
      cx=c.px; cy=c.py;
    }
    if(Math.hypot(cx-nozzleX,cy-nozzleY) < 18+c.r){
      c.taken=true;
      const gain=Math.ceil(c.val*(currentMode==='chaos'?2:1)*(1+(st.coin||0)));
      collectedGold+=gain;
      coinCombo++; lastCoinT=simTick*SIM_DT;
      livePot += gain*12*mult; addUlt(0.004);
      missionAdd('coins',gain);
      addParticle(cx,cy,'#ffd35a',6,0.8);
      floatText(cx,cy,'+'+gain+'g','#ffd35a');
      sfx.coin(coinCombo); buzz(8);
    }
  }
  while(ci<coins.length){
    const c=coins[ci];
    const cx=c.px===null?c.x:c.px;
    if(c.taken || cx<camX-80) ci++; else break;
  }


  // Våbenkasser / survival-loot
  for(let i=wi;i<weaponCrates.length;i++){
    const c=weaponCrates[i];
    const baseX=c.px===null?c.x:c.px;
    if(baseX>wx+W+140) break;
    if(c.taken) continue;
    let cx, cy;
    if(c.px===null){
      const sc=sampleTrack(c.x);
      cx=c.x; cy=lerp(sc.top+42,sc.bot-42,c.tF);
    } else { cx=c.px; cy=c.py; }
    const dx=cx-nozzleX, dy=cy-nozzleY;
    const crateVac=vacLen*(c.kind==='weapon'?0.85:0.72);
    if(dx>-18 && dx<crateVac && Math.abs(dy)<vacHalf+34){
      if(c.px===null){ c.px=cx; c.py=cy; }
      const pull=(5.2+(st.magnet||0)*3.5+(dwarf.magnet>0?4:0))*dt;
      c.px += (nozzleX-c.px)*pull;
      c.py += (nozzleY-c.py)*pull;
      cx=c.px; cy=c.py;
    }
    if(Math.hypot(cx-nozzleX,cy-nozzleY)<24+c.r){
      collectWeaponCrate(c,cx,cy);
    }
  }
  while(wi<weaponCrates.length){
    const c=weaponCrates[wi];
    const cx=c.px===null?c.x:c.px;
    if(c.taken || cx<camX-120) wi++; else break;
  }

  // Farer
  for(let i=hi;i<hazards.length;i++){
    const h=hazards[i];
    if(h.x>wx+W) break;
    if(h.dead) continue;
    const sh=sampleTrack(h.x);
    const hy=hazardY(h,sh);
    const d=Math.hypot(h.x-wx,hy-dwarf.y);
    const rr=dwarf.hitR+h.hitR;
    if(d<rr){
      if(dwarf.dash>0 || dwarf.inv>0 || dwarf.shield>0){
        killHazard(h,hy,'PARRY',0.8); smashed++; missionAdd('bats',1);
        sfx.smash();
      } else {
        damageOrEnd(h.type==='bat'?'Flagermus i skægget.':h.type==='rock'?'Sten direkte i karrieren.':'Spiddet. Av.');
        if(state!=='play') return;
      }
    } else if(d<rr+16){
      h.near=true;
    }
    if(!h.dead && h.near && !h.counted && h.x<wx-30){
      h.counted=true; nearCount++;
      mult+=0.06; livePot+=45*mult; addUlt(0.03);
      floatText(h.x,hy,'TÆT PÅ! +'+Math.floor(45*mult),'#41e8ff');
      sfx.near(); pumpMult();
    }
  }
  while(hazards[hi] && (hazards[hi].dead || hazards[hi].x<wx-240)) hi++;

  if(simTick%3===0){
    runGhost.push({x:Math.round(wx), f:Math.round(dwarf.y/H*1000)/1000});
    if(runGhost.length>1600) runGhost.shift();
  }

  if(introPhase===1){
    if(inputLevel>0.7) heldT+=dt;
    if(heldT>0.35){ introPhase=2; $('introText').textContent='SLIP = FALD'; }
  } else if(introPhase===2){
    if(!inputDown){ introPhase=0; $('intro').style.display='none'; save.seenIntro=true; }
  }

  hudDirty=true;
}

function damageOrEnd(reason){
  if(dwarf.inv>0) return;
  if(shieldHp>0){
    shieldHp--; dwarf.inv=1.0;
    flash('REDDET! HP -1');
    addParticle(camX+dwarf.sx,dwarf.y,'#41e8ff',22,1.2);
    flashScreen('#41e8ff',.3); shake(10);
    sfx.hit();
    return;
  }
  beginDeath(reason);
}
function beginDeath(reason){
  state='dying';
  deathReason=reason||'Dværgen ramte noget. Sikkert væggen. Den var stor.';
  dieT=0.8;
  const wx=camX+dwarf.sx;
  addParticle(wx,dwarf.y,'#ff9d3d',26,1.8);
  addParticle(wx,dwarf.y,'#ff496c',20,1.4);
  addParticle(wx,dwarf.y,'#bfc7d9',14,1.2);
  flashScreen('#ff496c',.5); shake(22);
  sfx.crash();
  if(introPhase){ introPhase=0; $('intro').style.display='none'; }
  engineUpdate();
}

function handleGate(g, geom, st){
  let amount=0, label='';
  if(g.type==='bank'){
    amount=livePot*(1.0+(st.bank||0))*(bankBoostT>0?1.5:1);
    banked += amount; livePot=livePot*(st.refund||0);
    mult=Math.max(1,mult*(0.52-(st.bank||0)*.05));
    skips=0; label='BANK +'+fmt(amount); addUlt(0.05);
    sfx.bank(amount>2500); flashScreen('#63ff9a',.3); freezeT=Math.max(freezeT,0.07); shake(6);
  } else if(g.type==='split'){
    amount=livePot*(0.55+(st.split||0));
    banked += amount; livePot-=amount;
    mult=Math.max(1,mult*.78);
    label='SPLIT +'+fmt(amount);
    sfx.split(); flashScreen('#41e8ff',.22); freezeT=Math.max(freezeT,0.05); shake(4);
  } else if(g.type==='greed'){
    mult *= 1.38+(st.greed||0)*.45;
    livePot += 220*mult;
    label='GRÅDIG x'+mult.toFixed(2);
    sfx.skip(); flashScreen('#ff3df2',.25); shake(5); pumpMult();
  } else if(g.type==='perfect'){
    const precision=1-Math.abs(geom.y-dwarf.y)/geom.gap;
    if(precision>.72 || autoPerfectN>0){
      if(autoPerfectN>0 && precision<=.72){ autoPerfectN--; floatText(g.x,geom.y-30,'AUTO-PERFEKT','#b388ff'); }
      amount=livePot*(0.75+(st.perfect||0));
      banked += amount; livePot*=.3; mult*=1.18;
      perfects++;
      label='PERFEKT +'+fmt(amount);
      if(perfects>=3) unlock('perfect');
      sfx.perfect(); flashScreen('#ffd35a',.35); freezeT=Math.max(freezeT,0.07); shake(8);
    } else {
      amount=livePot*.35; banked+=amount; livePot*=.65;
      label='SKÆV +'+fmt(amount);
      sfx.split(); freezeT=Math.max(freezeT,0.04);
    }
  }
  missionAdd('bank',Math.floor(amount));
  addParticle(g.x,geom.y,GATE_COLOR[g.type],20,1.2);
  floatText(g.x,geom.y,label,'#fff');
  if(banked>=20000) unlock('bankman');
}


/* ===== 17-run-slut.js ===== */
/* ================= RUN SLUT ================= */
/* Belønnings-kurver: afkoblet fra den eksploderende score.
   sqrt-dæmpning gør at et 150-mio-run og et 2-mio-run giver næsten det samme,
   og et hårdt loft sikrer at fremgang tager mange runs (uger), ikke 3 runs. */
function heroXpForRun(final, smashed, wave, perfectsN, distV, xpStat){
  const base=6;
  const scorePart=Math.min(170, Math.sqrt(Math.max(0,final))/9);
  const skillPart=(smashed||0)*1.1 + (wave>1?wave*4:0) + (perfectsN||0)*3 + Math.floor((distV||0)/2600)*4;
  return Math.round(Math.min(340, (base+scorePart+skillPart)*(1+(xpStat||0)*0.4)));
}
function accXpForRun(final, smashed, survived, campClear, xpStat){
  const scorePart=Math.min(120, Math.sqrt(Math.max(0,final))/13);
  const bonus=10 + (smashed||0)*0.7 + (survived?18:0) + (campClear?35:0);
  return Math.round(Math.min(250, (scorePart+bonus)*(1+(xpStat||0)*0.4)));
}
function dataForRun(final){
  return Math.round(Math.min(24, Math.sqrt(Math.max(0,final))/80));
}
function gradeFor(final, oldBest, survived){
  if(duelTarget) return lastDuelWon ? 'DUELVINDER 👑' : 'Duel tabt';
  if(final>0 && oldBest>0 && final>=oldBest) return 'MINEKONGE 👑 · NY REKORD';
  if(oldBest<=0) return final>0 ? 'Ny i minen' : 'Grus';
  const r=final/oldBest;
  if(r>=0.8) return 'Sjakbajs';
  if(r>=0.5) return 'Minearbejder';
  if(r>=0.25) return 'Lærling';
  return 'Grus';
}
function endRun(survived,reason){
  if(state==='over') return;
  state='over';
  $('pauseOv').style.display='none';
  $('duelBar').style.display='none';
  if(introPhase){ introPhase=0; $('intro').style.display='none'; }
  const st=runStatsCache||{};
  const final=Math.floor(banked + (survived?livePot:(livePot*Math.max(0,(st.salvage||0)))));
  lastFinal=final; lastSurvived=survived;
  const oldBest=save.best;

  if(currentMode==='daily'){
    ensureDailyRun();
    save.dailyRun.tries++;
    save.dailyRun.best=Math.max(save.dailyRun.best, final);
  }
  lastCampaignClear=false;
  if(currentMode==='campaign' && activeCampaignLevel){
    if(!save.campaign) save.campaign={unlocked:1,current:1,stars:{}};
    lastCampaignClear=campaignClearCheck(final,survived);
    const stars=campaignStarCount(final,survived);
    const prev=save.campaign.stars[activeCampaignLevel.id]||0;
    if(stars>prev){
      save.campaign.stars[activeCampaignLevel.id]=stars;
      const reward=Math.floor(activeCampaignLevel.reward*(stars-prev));
      save.gold+=reward;
      gainXP(Math.floor(reward*.55));
      toast('Kampagne: '+stars+'★ · +'+reward+'g');
    }
    if(lastCampaignClear && activeCampaignLevel.id>=save.campaign.unlocked){
      save.campaign.unlocked=Math.min(CAMPAIGN_LEVELS.length, activeCampaignLevel.id+1);
      save.campaign.current=Math.min(CAMPAIGN_LEVELS.length, activeCampaignLevel.id+1);
    }
  }

  const goldGain = Math.floor(collectedGold + Math.min(450, final/180) + (save.research.passiveGold||0));
  save.gold += Math.max(0, goldGain);
  save.runs++;
  if(final>save.best){ save.best=final; save.bestDist=Math.floor(dist); }
  // Meta-fremgang er afkoblet fra den eksploderende score: dæmpet (sqrt) + hårdt loft per run.
  // Score må gerne være kæmpestor (flex) — men XP/data tjener du langsomt og jævnt.
  const xpStat=st.xp||0;
  gainXP(accXpForRun(final, smashed, survived, lastCampaignClear, xpStat));
  // Helt-EXP til den valgte helt (også i fair modes — det er stadig din helt)
  const heroKey=activeChar();
  const heroXP=heroXpForRun(final, smashed, (currentMode==='survival'?survivalWave:1), perfects, dist, xpStat);
  lastHeroXP=heroXP; lastHeroKey=heroKey;
  gainCharXP(heroKey, heroXP);
  // Data fra run (krystaller giver løbende i minen; dette er en lille bonus oveni — også loftet)
  const runDataBonus=dataForRun(final);
  if(runDataBonus>0) gainData(runDataBonus);
  if(lastCampaignClear) gainData(6 + (activeCampaignLevel?activeCampaignLevel.id:0));
  lastRunData=runData;
  save.leaderboard.push({score:final,bank:Math.floor(banked),peak:peak,seed:currentSeed,mode:modeMods.label,at:Date.now()});
  save.leaderboard=save.leaderboard.sort(function(a,b){return b.score-a.score;}).slice(0,60);
  saveGhost(currentSeed, runGhost, final);

  if(!survived) unlock('firstCrash');
  if(survived) unlock('finisher');
  if(skips>=5) unlock('greedy');
  if(save.gold>=2000) unlock('rich');

  lastDuelWon=false;
  if(duelTarget){
    lastDuelWon = final>duelTarget.score;
    if(lastDuelWon){ save.duelWins++; save.wins++; unlock('duelist'); }
  }
  persist();

  $('oScore').textContent=fmt(final);
  $('oBank').textContent=fmt(banked);
  $('oPeak').textContent='x'+peak.toFixed(2);
  $('oDist').textContent=fmt(dist/12)+' m';
  const hcName=(DATA.pilots[lastHeroKey]&&DATA.pilots[lastHeroKey].name) || (CHARACTERS[lastHeroKey]&&CHARACTERS[lastHeroKey].role) || 'Bram Jernskæg';
  $('oHeroXp').textContent='+'+fmt(lastHeroXP)+' · '+hcName+' Lv'+charLevel(lastHeroKey);
  $('oData').textContent='+'+fmt(lastRunData);
  $('oGrade').textContent=gradeFor(final,oldBest,survived);

  if(duelTarget){
    const diff=Math.abs(final-duelTarget.score);
    $('overTitle').textContent = lastDuelWon ? 'DU VANDT! 👑' : 'Tabt.';
    $('overText').textContent = lastDuelWon
      ? 'Du slog '+duelTarget.name+' med '+fmt(diff)+' point. Send revanchen.'
      : duelTarget.name+' beholder tronen. Der manglede '+fmt(diff)+' point.';
  } else if(currentMode==='campaign' && activeCampaignLevel){
    const stars=campaignStarCount(final,survived);
    $('overTitle').textContent = lastCampaignClear ? 'BANE KLARET! '+stars+'★' : 'Bane fejlet.';
    $('overText').textContent = lastCampaignClear
      ? activeCampaignLevel.name+' klaret. Næste mine låst op, fordi mennesker åbenbart kræver belønning for ikke at dø.'
      : 'Mål: '+objectiveText(activeCampaignLevel.goal)+'. Du var ikke helt der endnu.';
  } else {
    $('overTitle').textContent = survived ? 'MÅL!' : 'Crash.';
    $('overText').textContent = reason || 'Dværgen ramte noget. Sikkert væggen. Den var stor.';
  }
  $('shareBtn').textContent = (currentMode==='campaign' && lastCampaignClear) ? 'Næste bane' : (currentMode==='survival' ? 'Del overlevelse' : (duelTarget ? 'Send revanche' : 'Udfordr en ven'));
  const rb=$('retryBtn');
  if(currentMode==='daily' && save.dailyRun.tries>=3){ rb.disabled=true; rb.textContent='I morgen igen'; }
  else { rb.disabled=false; rb.textContent='Prøv igen'; }

  const go=$('gameOver');
  go.style.display='flex';
  go.classList.remove('arm');
  setTimeout(function(){ go.classList.add('arm'); }, 350);
  hudDirty=true; hudT=1;
  engineUpdate();
}


/* ===== 18-pause.js ===== */
/* ================= PAUSE ================= */
function pauseGame(){
  if(state!=='play') return;
  state='pause';
  inputDown=false;
  $('pauseOv').style.display='flex';
  engineUpdate();
  persist();
}
function resumeGame(){
  if(state!=='pause') return;
  $('pauseOv').style.display='none';
  state='play';
  last=now(); acc=0;
  requestAnimationFrame(loop);
}


/* ===== 19-duel-links-deling.js ===== */
/* ================= DUEL-LINKS & DELING ================= */
function buildChallengeURL(scoreVal){
  return location.origin+location.pathname+'#duel='+currentSeed+'x'+scoreVal+'x'+encodeURIComponent(save.name||'Dværg');
}
async function shareChallenge(){
  if(lastFinal<=0){ toast('Spil et run først.'); return; }
  const name=await ensureName();
  if(!name) return;
  const url=buildChallengeURL(lastFinal);
  const text='⛏️ Slå mine '+fmt(lastFinal)+' point i GRÅDIG Dværgkast! Samme bane, samme vilkår.';
  if(navigator.share){
    try{ await navigator.share({title:'GRÅDIG Dværgkast', text:text, url:url}); toast('Udfordring sendt!'); return; }
    catch(e){ if(e && e.name==='AbortError') return; }
  }
  try{ await navigator.clipboard.writeText(text+' '+url); toast('Link kopieret — send det til en ven!'); }
  catch(e){ toast('Kunne ikke dele linket.'); }
}
let nameResolve=null;
function ensureName(){
  return new Promise(function(res){
    if(save.name){ res(save.name); return; }
    nameResolve=res;
    $('nameInput').value='';
    $('nameDlg').style.display='flex';
    setTimeout(function(){ $('nameInput').focus(); },60);
  });
}
$('nameOk').onclick=function(){
  const v=($('nameInput').value||'').trim().slice(0,14)||'Dværg';
  save.name=v; persist();
  $('nameDlg').style.display='none';
  if(nameResolve){ nameResolve(v); nameResolve=null; }
};
$('nameCancel').onclick=function(){
  $('nameDlg').style.display='none';
  if(nameResolve){ nameResolve(null); nameResolve=null; }
};
function parseDuelHash(){
  const h=location.hash||'';
  if(h.indexOf('#duel=')!==0) return false;
  const parts=h.slice(6).split('x');
  if(parts.length<3) return false;
  const seed=Number(parts[0])>>>0;
  const sc=Math.max(1,Math.floor(Number(parts[1])||0));
  let name='Ukendt dværg';
  try{ name=decodeURIComponent(parts.slice(2).join('x')).slice(0,14)||name; }catch(e){}
  if(!seed||!sc) return false;
  setTimeout(function(){
    audioEnsure(); engineStart();
    startDuel(seed, sc, name);
  }, 300);
  return true;
}


/* ===== 20-hud.js ===== */
/* ================= HUD ================= */

function campaignProgress(){
  if(!activeCampaignLevel) return 0;
  const g=activeCampaignLevel.goal;
  const vals=[];
  if(g.finish) vals.push(clamp((camX+dwarf.sx)/Math.max(1,trackEndX-40),0,1));
  if(g.score) vals.push(clamp(score/g.score,0,1));
  if(g.bank) vals.push(clamp(banked/g.bank,0,1));
  if(g.coins) vals.push(clamp(collectedGold/g.coins,0,1));
  if(g.skips) vals.push(clamp(skips/g.skips,0,1));
  if(g.perfect) vals.push(clamp(perfects/g.perfect,0,1));
  if(g.smash) vals.push(clamp(smashed/g.smash,0,1));
  return vals.length ? Math.min.apply(null,vals) : 0;
}
function campaignClearCheck(final,survived){
  if(!activeCampaignLevel) return false;
  const g=activeCampaignLevel.goal;
  if(g.finish && !survived) return false;
  if(g.score && final<g.score) return false;
  if(g.bank && banked<g.bank) return false;
  if(g.coins && collectedGold<g.coins) return false;
  if(g.skips && skips<g.skips) return false;
  if(g.perfect && perfects<g.perfect) return false;
  if(g.smash && smashed<g.smash) return false;
  return true;
}
function campaignStarCount(final,survived){
  if(!activeCampaignLevel) return 0;
  let stars = campaignClearCheck(final,survived) ? 1 : 0;
  if(!stars) return 0;
  const g=activeCampaignLevel.goal;
  if(final >= (g.score||12000)*1.25 || banked >= (g.bank||9000)*1.25) stars++;
  if(survived && peak>=8) stars++;
  return clamp(stars,1,3);
}

function hudTick(dt){
  hudT+=dt;
  if(!hudDirty || hudT<0.08) return;
  hudT=0; hudDirty=false;
  $('liveVal').textContent=fmt(livePot);
  $('bankVal').textContent=fmt(banked);
  $('goldVal').textContent=fmt(collectedGold);
  $('multVal').textContent='x'+mult.toFixed(2);
  $('skipVal').textContent=skips;
  $('hpVal').textContent=shieldHp;
  const cdEl=$('hammerCd'), hb=$('hammerBtn');
  if(hammerCd>0){ cdEl.textContent=hammerCd.toFixed(1); hb.classList.add('cd'); }
  else { cdEl.textContent='klar'; hb.classList.remove('cd'); }
  const ub=$('ultBtn');
  if(ub){
    const c=CHARACTERS[runChar]||CHARACTERS.bram;
    ub.style.setProperty('--ult', ultCharge.toFixed(3));
    ub.style.setProperty('--ultcol', c.color||'#7CF6E3');
    $('ultLbl').textContent = ultCharge>=1 ? (c.ultShort||'KLAR') : Math.floor(ultCharge*100)+'%';
    ub.classList.toggle('ready', ultCharge>=1);
  }
  if(duelTarget && state==='play'){
    $('duelFill').style.width=Math.min(100, score/duelTarget.score*100).toFixed(1)+'%';
  } else if(currentMode==='campaign' && activeCampaignLevel && state==='play'){
    $('duelFill').style.width=(campaignProgress()*100).toFixed(1)+'%';
  }
}


/* ===== 21-loop.js ===== */
/* ================= LOOP ================= */
function loop(){
  if(state==='menu' || state==='over' || state==='pause') return;
  const n=now();
  const dt=Math.min(0.1, n-last);
  last=n;
  if(state==='play'){
    if(freezeT>0){
      freezeT-=dt;
    } else {
      acc+=dt;
      let steps=0;
      while(acc>=SIM_DT && steps<5){
        stepSim();
        acc-=SIM_DT;
        steps++;
        if(state!=='play') break;
      }
      if(steps>=5) acc=0;
    }
  } else if(state==='dying'){
    dieT-=dt;
    if(dieT<=0){
      endRun(false, deathReason);
      return;
    }
  }
  const fxScale = state==='dying' ? 0.35 : 1;
  updateFX(dt*fxScale, dt);
  draw(state==='play' ? clamp(acc/SIM_DT,0,1) : 0);
  engineUpdate();
  heartbeatUpdate(dt);
  hudTick(dt);
  requestAnimationFrame(loop);
}
function updateFX(dt, realDt){
  for(const p of particles){ p.x+=p.vx*dt; p.y+=p.vy*dt; p.vy+=220*dt; p.life-=dt; }
  particles=particles.filter(function(p){return p.life>0;});
  for(const f of floating){ f.y-=35*dt; f.life-=dt*0.8; }
  floating=floating.filter(function(f){return f.life>0;});
  shakeMag=Math.max(0, shakeMag - realDt*46);
  flashA=Math.max(0, flashA - realDt*1.6);
}


/* ===== 22-sprites-erstatter-shadowblur-mobil-fps.js ===== */
/* ================= SPRITES (erstatter shadowBlur => mobil-fps) ================= */
const spriteCache={};
function glowSprite(color){
  if(spriteCache[color]) return spriteCache[color];
  const s=48;
  const c=document.createElement('canvas'); c.width=s; c.height=s;
  const g=c.getContext('2d');
  const grd=g.createRadialGradient(s/2,s/2,1,s/2,s/2,s/2);
  grd.addColorStop(0,color);
  grd.addColorStop(0.4,color+'aa');
  grd.addColorStop(1,color+'00');
  g.fillStyle=grd;
  g.fillRect(0,0,s,s);
  spriteCache[color]=c;
  return c;
}
let coinSpr1=null, coinSpr5=null;
function makeCoinSprite(big){
  const r=big?8:5, pad=13, s=(r+pad)*2;
  const c=document.createElement('canvas'); c.width=s; c.height=s;
  const g=c.getContext('2d');
  const grd=g.createRadialGradient(s/2,s/2,1,s/2,s/2,s/2);
  grd.addColorStop(0,'#ffd35a'); grd.addColorStop(0.45,'#ffd35a55'); grd.addColorStop(1,'#ffd35a00');
  g.fillStyle=grd; g.fillRect(0,0,s,s);
  g.fillStyle='#ffd35a'; g.beginPath(); g.arc(s/2,s/2,r,0,Math.PI*2); g.fill();
  g.fillStyle='#8a5d00'; g.beginPath(); g.arc(s/2,s/2,r*0.55,0,Math.PI*2); g.fill();
  if(big){ g.fillStyle='#ffd35a'; g.font='900 9px system-ui'; g.textAlign='center'; g.textBaseline='middle'; g.fillText('5',s/2,s/2+0.5); }
  return c;
}
let starsBuilt=false;
function buildStars(){
  if(starsBuilt) return;
  starsBuilt=true;
  starFar=document.createElement('canvas'); starFar.width=512; starFar.height=512;
  starNear=document.createElement('canvas'); starNear.width=512; starNear.height=512;
  const r1=mulberry32(987654);
  let g=starFar.getContext('2d');
  for(let i=0;i<46;i++){
    g.fillStyle=i%3?'#41e8ff':'#ff3df2';
    g.globalAlpha=0.16+r1()*0.2;
    g.beginPath(); g.arc(r1()*512, r1()*512, 1+r1()*1.5, 0, Math.PI*2); g.fill();
  }
  g=starNear.getContext('2d');
  for(let i=0;i<26;i++){
    g.fillStyle=i%4?'#8d63ff':'#ffd35a';
    g.globalAlpha=0.18+r1()*0.25;
    g.beginPath(); g.arc(r1()*512, r1()*512, 1.5+r1()*2, 0, Math.PI*2); g.fill();
  }
}
let trackGrad=null;
function buildVignettes(){
  trackGrad=null;
  const w=Math.max(2,W), h=Math.max(2,H);
  vignCanvas=document.createElement('canvas'); vignCanvas.width=w; vignCanvas.height=h;
  let g=vignCanvas.getContext('2d');
  let grd=g.createRadialGradient(w/2,h/2,Math.min(w,h)*.2,w/2,h/2,Math.max(w,h)*.65);
  grd.addColorStop(0,'#00000000'); grd.addColorStop(1,'#00000088');
  g.fillStyle=grd; g.fillRect(0,0,w,h);
  dangerCanvas=document.createElement('canvas'); dangerCanvas.width=w; dangerCanvas.height=h;
  g=dangerCanvas.getContext('2d');
  grd=g.createRadialGradient(w/2,h/2,Math.min(w,h)*.25,w/2,h/2,Math.max(w,h)*.62);
  grd.addColorStop(0,'#ff496c00'); grd.addColorStop(1,'#ff496c55');
  g.fillStyle=grd; g.fillRect(0,0,w,h);
}


/* ===== 23-tegning.js ===== */
/* ================= TEGNING ================= */
function draw(alpha){
  ctx.setTransform(DPR,0,0,DPR,0,0);
  const cam = lerp(pCamX, camX, alpha);
  const dy = lerp(dwarf.py, dwarf.y, alpha);
  let shx=0, shy=0;
  if(shakeMag>0.2){ shx=(Math.random()-0.5)*shakeMag; shy=(Math.random()-0.5)*shakeMag; }
  drawBackground(cam);
  ctx.save();
  ctx.translate(shx, shy);
  drawTrack(cam);
  drawFlags(cam);
  drawGhost(cam);
  if(state==='play') drawVacuum(dy);
  drawGates(cam);
  drawCoins(cam);
  drawWeaponCrates(cam);
  drawHazards(cam);
  if(state==='play') drawDwarf(dy);
  drawParticles(cam);
  ctx.restore();
  ctx.drawImage(vignCanvas,0,0,W,H);
  if(state==='play'){
    const danger=clamp((mult-8)/14,0,1);
    if(danger>0.02){
      ctx.globalAlpha=danger*(0.45+0.45*Math.sin(now()*6));
      ctx.drawImage(dangerCanvas,0,0,W,H);
      ctx.globalAlpha=1;
    }
  }
  if(flashA>0){
    ctx.globalAlpha=Math.min(0.55,flashA);
    ctx.fillStyle=flashCol;
    ctx.fillRect(0,0,W,H);
    ctx.globalAlpha=1;
  }
}
function drawBackground(cam){
  ctx.fillStyle='#070711';
  ctx.fillRect(0,0,W,H);
  buildStars();
  ctx.globalAlpha=0.5;
  const o1=-((cam*0.12)%512);
  for(let x=o1-512;x<W+512;x+=512){
    ctx.drawImage(starFar,x,0);
    if(H>512) ctx.drawImage(starFar,x,512);
  }
  ctx.globalAlpha=0.6;
  const o2=-((cam*0.3)%512);
  for(let x=o2-512;x<W+512;x+=512){
    ctx.drawImage(starNear,x,64);
    if(H>576) ctx.drawImage(starNear,x,576);
  }
  ctx.globalAlpha=0.10;
  ctx.strokeStyle='#41e8ff';
  ctx.lineWidth=1;
  const off=(cam*0.6)%73;
  ctx.beginPath();
  for(let i=0;i<14;i++){
    const y=(i*73+off)%H;
    ctx.moveTo(0,y); ctx.lineTo(W,y-30);
  }
  ctx.stroke();
  ctx.globalAlpha=1;
}
function drawTrack(cam){
  const start=cam-80, end=cam+W+120;
  ctx.beginPath();
  let first=true;
  for(let x=start;x<end;x+=42){
    const s=sampleTrack(x);
    if(first){ctx.moveTo(x-cam,s.top); first=false;} else ctx.lineTo(x-cam,s.top);
  }
  for(let x=end;x>=start;x-=42){
    const s=sampleTrack(x);
    ctx.lineTo(x-cam,s.bot);
  }
  ctx.closePath();
  if(!trackGrad){
    trackGrad=ctx.createLinearGradient(0,0,W,H);
    trackGrad.addColorStop(0,'#11113a'); trackGrad.addColorStop(1,'#191019');
  }
  ctx.fillStyle=trackGrad;
  ctx.fill();
  strokeWall(cam,start,end,'top','#41e8ff');
  strokeWall(cam,start,end,'bot','#ff3df2');
}
function strokeWall(cam,start,end,which,color){
  ctx.lineJoin='round';
  ctx.strokeStyle=color;
  const passes=[[13,0.20],[4,1]];
  for(let p=0;p<2;p++){
    ctx.lineWidth=passes[p][0]; ctx.globalAlpha=passes[p][1];
    ctx.beginPath();
    let first=true;
    for(let x=start;x<end;x+=30){
      const s=sampleTrack(x);
      const y=which==='top'?s.top:s.bot;
      if(first){ctx.moveTo(x-cam,y); first=false;} else ctx.lineTo(x-cam,y);
    }
    ctx.stroke();
  }
  ctx.globalAlpha=1;
}
function drawFlags(cam){
  if(save.bestDist>800 && save.bestDist<trackEndX-200) drawFlag(cam, save.bestDist, '#ffd35a', 'REKORD');
  drawFlag(cam, trackEndX-40, '#63ff9a', 'MÅL');
}
function drawFlag(cam,x,color,label){
  const sxx=x-cam;
  if(sxx<-60||sxx>W+60) return;
  const s=sampleTrack(x);
  ctx.strokeStyle='#bfc7d9'; ctx.lineWidth=3;
  ctx.beginPath(); ctx.moveTo(sxx,s.top+6); ctx.lineTo(sxx,s.top+58); ctx.stroke();
  ctx.fillStyle=color;
  ctx.beginPath(); ctx.moveTo(sxx,s.top+8); ctx.lineTo(sxx+34,s.top+18); ctx.lineTo(sxx,s.top+28); ctx.closePath(); ctx.fill();
  ctx.font='900 11px system-ui'; ctx.textAlign='left';
  ctx.fillText(label, sxx+4, s.top+72);
}
function drawGhost(cam){
  if(!ghost) return;
  ctx.globalAlpha=0.25;
  ctx.strokeStyle='#ffffff'; ctx.lineWidth=2.5;
  ctx.beginPath();
  let first=true;
  const p=ghost.path;
  for(let i=0;i<p.length;i+=2){
    const gx=p[i].x-cam;
    if(gx<-60){first=true; continue;}
    if(gx>W+60) break;
    const gy=p[i].f*H;
    if(first){ctx.moveTo(gx,gy); first=false;} else ctx.lineTo(gx,gy);
  }
  ctx.stroke();
  ctx.globalAlpha=1;
}
function drawVacuum(dy){
  const st=runStatsCache;
  const x=dwarf.sx+26, y=dy-3;
  const len=145+(st.magnet||0)*130+(dwarf.magnet>0?120:0);
  const half=36+(st.magnet||0)*38+(dwarf.magnet>0?26:0);
  ctx.save();
  ctx.globalAlpha=dwarf.magnet>0?.30:.16;
  const grd=ctx.createLinearGradient(x,y,x+len,y);
  grd.addColorStop(0,'#ffd35aaa'); grd.addColorStop(.45,'#41e8ff55'); grd.addColorStop(1,'#41e8ff00');
  ctx.fillStyle=grd;
  ctx.beginPath();
  ctx.moveTo(x,y-14);
  ctx.quadraticCurveTo(x+len*.45,y-half,x+len,y-half*.45);
  ctx.lineTo(x+len,y+half*.45);
  ctx.quadraticCurveTo(x+len*.45,y+half,x,y+14);
  ctx.closePath(); ctx.fill();
  ctx.restore();
}
function drawGates(cam){
  ctx.textAlign='center';
  ctx.font='900 12px system-ui';
  for(let i=gi;i<gates.length;i++){
    const g=gates[i];
    const sxx=g.x-cam;
    if(sxx>W+80) break;
    if(g.used||sxx<-80) continue;
    const geom=gateGeom(g);
    const col=GATE_COLOR[g.type];
    const pulse=1+0.10*Math.sin(now()*5+g.x*0.01);
    ctx.strokeStyle=col;
    ctx.globalAlpha=0.25; ctx.lineWidth=11*pulse;
    ctx.beginPath(); ctx.moveTo(sxx,geom.y-geom.gap); ctx.lineTo(sxx,geom.y+geom.gap); ctx.stroke();
    ctx.globalAlpha=1; ctx.lineWidth=4;
    ctx.beginPath(); ctx.moveTo(sxx,geom.y-geom.gap); ctx.lineTo(sxx,geom.y+geom.gap); ctx.stroke();
    const spr=glowSprite(col);
    ctx.drawImage(spr,sxx-13,geom.y-geom.gap-13,26,26);
    ctx.drawImage(spr,sxx-13,geom.y+geom.gap-13,26,26);
    ctx.fillStyle=col;
    const lbl=g.type==='bank'?'BANK':g.type==='split'?'SPLIT':g.type==='greed'?'GRÅDIG':'PERFEKT';
    ctx.fillText(lbl,sxx,geom.y-geom.gap-10);
    if(g.type==='perfect'){
      ctx.globalAlpha=0.85;
      ctx.fillRect(sxx-7,geom.y-2,14,4);
      ctx.globalAlpha=1;
    }
  }
}
function drawCoins(cam){
  if(!coinSpr1){ coinSpr1=makeCoinSprite(false); coinSpr5=makeCoinSprite(true); }
  for(let i=ci;i<coins.length;i++){
    const c=coins[i];
    const cx=c.px===null?c.x:c.px;
    const sxx=cx-cam;
    if(c.px===null && sxx>W+60) break;
    if(c.taken||sxx<-40||sxx>W+60) continue;
    let cy;
    if(c.px===null){
      const s=sampleTrack(c.x);
      cy=lerp(s.top+35,s.bot-35,c.tF);
    } else cy=c.py;
    const spr=c.val===5?coinSpr5:coinSpr1;
    ctx.drawImage(spr,sxx-spr.width/2,cy-spr.height/2);
  }
}

function drawWeaponCrates(cam){
  for(let i=wi;i<weaponCrates.length;i++){
    const c=weaponCrates[i];
    const cx=c.px===null?c.x:c.px;
    const sxx=cx-cam;
    if(c.px===null && sxx>W+80) break;
    if(c.taken||sxx<-60||sxx>W+80) continue;
    let cy;
    if(c.px===null){
      const sc=sampleTrack(c.x);
      cy=lerp(sc.top+42,sc.bot-42,c.tF);
    } else cy=c.py;
    const col=c.kind==='weapon'?'#ffd35a':c.kind==='medkit'?'#63ff9a':c.kind==='relic'?'#ff3df2':'#bfc7d9';
    ctx.save();
    ctx.translate(sxx,cy);
    ctx.rotate(Math.sin(now()*3+c.x*.01)*0.12);
    ctx.fillStyle='#111124';
    ctx.strokeStyle=col;
    ctx.lineWidth=3;
    ctx.shadowColor=col;
    ctx.shadowBlur=12;
    roundRect(ctx,-13,-13,26,26,6,true,true);
    ctx.shadowBlur=0;
    ctx.fillStyle=col;
    ctx.font='900 15px system-ui';
    ctx.textAlign='center';
    ctx.textBaseline='middle';
    ctx.fillText(c.kind==='weapon'?'⚔':c.kind==='medkit'?'+':c.kind==='relic'?'✦':'⚙',0,1);
    ctx.restore();
  }
}

function drawHazards(cam){
  for(let i=hi;i<hazards.length;i++){
    const h=hazards[i];
    const sxx=h.x-cam;
    if(sxx>W+80) break;
    if(h.dead||sxx<-80) continue;
    const s=sampleTrack(h.x);
    const y=hazardY(h,s);
    if(h.type==='bat'){
      ctx.drawImage(glowSprite('#ff3df2'),sxx-20,y-20,40,40);
      ctx.strokeStyle='#ff3df2'; ctx.fillStyle='#260026'; ctx.lineWidth=3;
      const flap=Math.sin(now()*14+h.phase)*6;
      ctx.beginPath();
      ctx.moveTo(sxx,y); ctx.quadraticCurveTo(sxx-22,y-20+flap,sxx-34,y+5);
      ctx.quadraticCurveTo(sxx-10,y-5,sxx,y);
      ctx.moveTo(sxx,y); ctx.quadraticCurveTo(sxx+22,y-20+flap,sxx+34,y+5);
      ctx.quadraticCurveTo(sxx+10,y-5,sxx,y);
      ctx.stroke();
      ctx.beginPath(); ctx.arc(sxx,y,8,0,Math.PI*2); ctx.fill();
    } else if(h.type==='rock'){
      ctx.fillStyle='#7f879c';
      ctx.beginPath();
      for(let k=0;k<8;k++){
        const a=k/8*Math.PI*2, rr=h.r*(.75+((k*31)%9)/18);
        const px=sxx+Math.cos(a)*rr, py=y+Math.sin(a)*rr;
        if(k===0)ctx.moveTo(px,py); else ctx.lineTo(px,py);
      }
      ctx.closePath(); ctx.fill();
      ctx.strokeStyle='#2a2f3d'; ctx.lineWidth=2; ctx.stroke();
    } else if(h.type==='saw'){
      const spin=now()*9+h.phase;
      ctx.save(); ctx.translate(sxx,y); ctx.rotate(spin);
      ctx.fillStyle='#9aa3b5'; ctx.strokeStyle='#3a4150'; ctx.lineWidth=2;
      ctx.beginPath();
      const teeth=10;
      for(let k=0;k<teeth*2;k++){
        const a=k/(teeth*2)*Math.PI*2;
        const rr=(k%2===0)?h.r:h.r*0.68;
        const px=Math.cos(a)*rr, py=Math.sin(a)*rr;
        if(k===0)ctx.moveTo(px,py); else ctx.lineTo(px,py);
      }
      ctx.closePath(); ctx.fill(); ctx.stroke();
      ctx.fillStyle='#2a2f3d'; ctx.beginPath(); ctx.arc(0,0,h.r*0.3,0,Math.PI*2); ctx.fill();
      ctx.restore();
      if(h.hpMax>1 && h.hp<h.hpMax){
        ctx.fillStyle='#ff496c'; ctx.fillRect(sxx-h.r,y-h.r-7,h.r*2*(h.hp/h.hpMax),3);
      }
    } else if(h.type==='crystal'){
      const pulse=0.5+0.5*Math.sin(now()*4+h.phase);
      ctx.drawImage(glowSprite('#7CF6E3'),sxx-26,y-26,52,52);
      ctx.save(); ctx.translate(sxx,y);
      const g=ctx.createLinearGradient(0,-h.r,0,h.r);
      g.addColorStop(0,'#b388ff'); g.addColorStop(.5,'#7CF6E3'); g.addColorStop(1,'#41e8ff');
      ctx.fillStyle=g; ctx.strokeStyle='#eafcff'; ctx.lineWidth=2;
      ctx.beginPath();
      ctx.moveTo(0,-h.r); ctx.lineTo(h.r*0.7,-h.r*0.2);
      ctx.lineTo(h.r*0.45,h.r); ctx.lineTo(-h.r*0.45,h.r);
      ctx.lineTo(-h.r*0.7,-h.r*0.2); ctx.closePath();
      ctx.globalAlpha=0.85+0.15*pulse; ctx.fill(); ctx.globalAlpha=1; ctx.stroke();
      ctx.strokeStyle='#ffffff66'; ctx.lineWidth=1;
      ctx.beginPath(); ctx.moveTo(0,-h.r); ctx.lineTo(0,h.r);
      ctx.moveTo(-h.r*0.7,-h.r*0.2); ctx.lineTo(h.r*0.7,-h.r*0.2); ctx.stroke();
      ctx.restore();
      ctx.fillStyle='#0a0f17cc'; ctx.fillRect(sxx-h.r,y-h.r-9,h.r*2,4);
      ctx.fillStyle='#7CF6E3'; ctx.fillRect(sxx-h.r,y-h.r-9,h.r*2*(h.hp/h.hpMax),4);
    } else {
      ctx.drawImage(glowSprite('#ff496c'),sxx-22,y-22,44,44);
      ctx.fillStyle='#ff496c';
      ctx.beginPath();
      if(h.edge==='top'){ ctx.moveTo(sxx,y+h.r); ctx.lineTo(sxx+h.r,y-h.r); ctx.lineTo(sxx-h.r,y-h.r); }
      else { ctx.moveTo(sxx,y-h.r); ctx.lineTo(sxx+h.r,y+h.r); ctx.lineTo(sxx-h.r,y+h.r); }
      ctx.closePath(); ctx.fill();
    }
  }
}
function drawDwarf(dy){
  const x=dwarf.sx, y=dy;
  ctx.save();
  if(dwarf.inv>0){
    ctx.globalAlpha=0.55+0.45*Math.sin(now()*30);
  }
  ctx.translate(x,y); ctx.rotate(dwarf.rot*.55);
  if(dwarf.inv>0 || dwarf.shield>0){
    ctx.strokeStyle=dwarf.shield>0?'#41e8ff':'#ffffff';
    ctx.lineWidth=3;
    ctx.globalAlpha=.8;
    ctx.beginPath(); ctx.arc(0,0,30,0,Math.PI*2); ctx.stroke();
    ctx.globalAlpha=dwarf.inv>0 ? 0.55+0.45*Math.sin(now()*30) : 1;
  }
  const grd=ctx.createRadialGradient(-30,0,2,-30,0,35);
  grd.addColorStop(0,'#fff'); grd.addColorStop(.3,'#ff9d3d'); grd.addColorStop(1,'#ff3d3d00');
  ctx.fillStyle=grd;
  ctx.beginPath(); ctx.ellipse(-34,0,38,14,0,0,Math.PI*2); ctx.fill();
  ctx.strokeStyle='#5b3618'; ctx.lineWidth=5; ctx.lineCap='round';
  ctx.beginPath(); ctx.moveTo(-2,15); ctx.lineTo(-18,26); ctx.moveTo(8,14); ctx.lineTo(22,25); ctx.stroke();
  ctx.fillStyle='#3b78ff'; ctx.strokeStyle='#101020'; ctx.lineWidth=2;
  roundRect(ctx,-16,-8,32,30,9,true,true);
  ctx.fillStyle='#2a2a35'; ctx.strokeStyle='#41e8ff'; ctx.lineWidth=2;
  roundRect(ctx,18,-6,22,13,5,true,true);
  ctx.fillStyle='#080812'; ctx.beginPath(); ctx.arc(40,0,6,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='#ffd35a'; ctx.font='900 8px system-ui'; ctx.textAlign='center';
  ctx.fillText((WEAPONS[currentWeaponKey()]?WEAPONS[currentWeaponKey()].name[0]:'Ø'),29,-10);
  ctx.strokeStyle='#101020';
  ctx.fillStyle='#f1b278';
  ctx.beginPath(); ctx.arc(4,-18,15,0,Math.PI*2); ctx.fill(); ctx.stroke();
  ctx.fillStyle='#c96f2a';
  ctx.beginPath();
  ctx.moveTo(-10,-12); ctx.quadraticCurveTo(4,16,20,-10); ctx.quadraticCurveTo(6,2,-10,-12); ctx.fill();
  ctx.fillStyle='#bfc7d9'; ctx.beginPath(); ctx.arc(4,-24,16,Math.PI,0); ctx.fill(); ctx.stroke();
  ctx.strokeStyle='#ffd35a'; ctx.lineWidth=3;
  ctx.beginPath(); ctx.moveTo(-8,-31); ctx.lineTo(-22,-42); ctx.moveTo(16,-31); ctx.lineTo(31,-42); ctx.stroke();
  ctx.fillStyle='#050505'; ctx.beginPath(); ctx.arc(0,-19,2,0,Math.PI*2); ctx.arc(10,-19,2,0,Math.PI*2); ctx.fill();
  ctx.strokeStyle='#5b3618'; ctx.lineWidth=4;
  ctx.beginPath(); ctx.moveTo(17,1); ctx.lineTo(32,-15); ctx.stroke();
  ctx.fillStyle='#929bad'; ctx.strokeStyle='#101020'; ctx.lineWidth=2;
  roundRect(ctx,25,-24,24,12,3,true,true);
  ctx.globalAlpha=.18; ctx.strokeStyle='#63ff9a'; ctx.lineWidth=1.5;
  ctx.beginPath(); ctx.arc(0,0,dwarf.hitR,0,Math.PI*2); ctx.stroke();
  ctx.restore();
}
function roundRect(c,x,y,w,h,r,fill,stroke){
  c.beginPath();
  c.moveTo(x+r,y); c.arcTo(x+w,y,x+w,y+h,r); c.arcTo(x+w,y+h,x,y+h,r);
  c.arcTo(x,y+h,x,y,r); c.arcTo(x,y,x+w,y,r); c.closePath();
  if(fill)c.fill(); if(stroke)c.stroke();
}
function drawParticles(cam){
  for(const p of particles){
    ctx.globalAlpha=clamp(p.life*2.2,0,1);
    ctx.drawImage(glowSprite(p.color),p.x-cam-7,p.y-7,14,14);
  }
  ctx.globalAlpha=1;
  ctx.font='900 15px system-ui';
  ctx.textAlign='center';
  for(const f of floating){
    ctx.globalAlpha=clamp(f.life,0,1);
    ctx.fillStyle='#000';
    ctx.fillText(f.text,f.x-cam+1.5,f.y+1.5);
    ctx.fillStyle=f.color;
    ctx.fillText(f.text,f.x-cam,f.y);
  }
  ctx.globalAlpha=1;
}
function drawIdle(){
  ctx.setTransform(DPR,0,0,DPR,0,0);
  ctx.fillStyle='#070711'; ctx.fillRect(0,0,W,H);
  buildStars();
  ctx.globalAlpha=.5;
  for(let x=0;x<W+512;x+=512){ ctx.drawImage(starFar,x,0); if(H>512) ctx.drawImage(starFar,x,512); }
  ctx.globalAlpha=1;
}


/* ===== 24-boot.js ===== */
/* ================= BOOT ================= */
resize();
buildStars();
drawIdle();
ensureDailyMissions();
ensureDailyRun();
$('soundBtn').textContent = save.sound ? '🔊' : '🔇';
const bootParams=new URLSearchParams(location.search);
if(!parseDuelHash() && bootParams.get('seed')){
  setTimeout(function(){ startGame('random', Number(bootParams.get('seed'))>>>0); }, 300);
}
refreshMenu();

if('serviceWorker' in navigator && location.protocol !== 'file:'){
  window.addEventListener('load', ()=>{
    navigator.serviceWorker.register('./src/pwa/sw.js').catch(err=>console.warn('Service worker ikke registreret:', err));
  });
}

